<template><view class="page"><view class="hero"><text class="eyebrow">NAMING REPORT</text><text class="title">高级命名报告</text><text class="desc">从寓意、音韵、匹配度与可用性多维解读候选名字。</text></view><view class="creator"><text class="section-title">创建演示报告</text><input v-model="name" placeholder="输入候选名字，如：青岚"/><button :disabled="!name.trim()" @click="create">生成报告</button><text class="note">当前使用演示评分，成员 C 输出稳定后接入真实分析。</text></view><view class="section-head"><text>我的报告</text><text>{{reports.length}} 份</text></view><view v-if="!reports.length" class="empty">还没有报告</view><view v-for="item in reports" :key="item.id" class="report"><view class="report-head"><view><text class="report-name">{{item.name}}</text><text class="date">{{formatDate(item.created_at)}}</text></view><text class="score">{{item.score}} 分</text></view><text class="summary">{{item.summary}}</text><view class="dimensions"><view v-for="(value,key) in item.dimensions" :key="key"><text>{{key}}</text><text>{{value}}</text><view><view :style="{width:`${value}%`}"></view></view></view></view><text class="disclaimer">演示结果仅供产品流程测试，不构成商标或注册建议。</text></view></view></template>
<script setup>import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import{createReport,getReports}from'@/services/phase3Mock.js';const name=ref(uni.getStorageSync('selectedName')||'');const reports=ref([]);onShow(()=>reports.value=getReports());const create=()=>{if(!name.value.trim())return;createReport(name.value.trim());reports.value=getReports();name.value='';uni.showToast({title:'报告已生成',icon:'success'});};const formatDate=v=>String(v||'').replace('T',' ').slice(0,16);</script>
<style scoped>.page{min-height:100vh;padding:32rpx 30rpx 90rpx;box-sizing:border-box;color:#292620;background:#f7f4ee}.hero{padding:32rpx;color:#fff;border-radius:25rpx;background:linear-gradient(135deg,#3a5146,#72897c)}.eyebrow,.title,.desc{display:block}.eyebrow{color:#dce5df;font-size:16rpx;letter-spacing:3rpx}.title{margin-top:8rpx;font-size:38rpx;font-weight:700}.desc{margin-top:10rpx;color:rgba(255,255,255,.7);font-size:21rpx}.creator,.report,.empty{margin-top:20rpx;padding:26rpx;border-radius:20rpx;background:#fff}.section-title{font-size:28rpx;font-weight:700}.creator input{height:78rpx;margin-top:20rpx;padding:0 20rpx;border-radius:12rpx;background:#f7f5f0}.creator button{margin-top:16rpx;color:#fff;background:#3f5c4e}.note,.disclaimer{display:block;margin-top:12rpx;color:#a0978b;font-size:18rpx}.section-head,.report-head{display:flex;align-items:center;justify-content:space-between}.section-head{margin:36rpx 4rpx 10rpx;font-size:27rpx;font-weight:700}.section-head text:last-child{color:#968d81;font-size:19rpx}.empty{color:#9b9287;text-align:center}.report-name,.date,.summary{display:block}.report-name{font-size:32rpx;font-weight:700}.date{margin-top:5rpx;color:#9d9488;font-size:18rpx}.score{color:#9b6730;font-size:30rpx;font-weight:700}.summary{margin-top:18rpx;color:#696259;font-size:21rpx;line-height:1.6}.dimensions{margin-top:20rpx}.dimensions>view{display:grid;grid-template-columns:130rpx 55rpx 1fr;align-items:center;gap:12rpx;margin-top:12rpx;font-size:19rpx}.dimensions>view>view{height:8rpx;overflow:hidden;border-radius:8rpx;background:#ece8e1}.dimensions>view>view>view{height:100%;background:#668474}</style>
